fn binary_search(v: i64, target: i64) -> i64 = {
    let n = vec_len(v);
    let mut lo = 0;
    let mut hi = n - 1;
    let mut result = 0 - 1;
    while lo <= hi {
        let mid = lo + (hi - lo) / 2;
        let val = vec_get(v, mid);
        if val == target {
            set result = mid;
            set lo = hi + 1
        } else if val < target {
            set lo = mid + 1
        } else {
            set hi = mid - 1
        }
    };
    result
};

